 * 
 * This tests the fix for the issue where callbackFlow closed with an exception
 * would not propagate that exception when combined directly with timeout.
 */
class TimeoutCallbackFlowTest : TestBase() {

    @Test
    fun testCallbackFlowCloseWithExceptionAndTimeout() = runTest {
        val flow = callbackFlow<Int> {
            close(IllegalStateException("Test Exception"))
        }.timeout(5.seconds)

        val exception = assertFailsWith<IllegalStateException> {
            flow.collect()
        }
        assertEquals("Test Exception", exception.message)
    }

    @Test
    fun testChannelFlowCloseWithExceptionAndTimeout() = runTest {
        val flow = channelFlow<Int> {
            close(IllegalStateException("Test Exception"))
        }.timeout(5.seconds)

        val exception = assertFailsWith<IllegalStateException> {
            flow.collect()
        }
        assertEquals("Test Exception", exception.message)
    }

    @Test
    fun testCallbackFlowCloseWithExceptionAndTimeoutWithCatch() = runTest {
        // Verify that adding catch in between also works (this was the workaround)
        val flow = callbackFlow<Int> {
            close(IllegalStateException("Test Exception"))
        }.catch { throw it }.timeout(5.seconds)

        val exception = assertFailsWith<IllegalStateException> {
            flow.collect()
        }
        assertEquals("Test Exception", exception.message)
    }

    @Test
    fun testCallbackFlowCloseNormallyWithTimeout() = runTest {
        // When closing normally (without exception), should complete normally
        val result = mutableListOf<Int>()
        val flow = callbackFlow {
            send(1)
            send(2)
            close()
            awaitClose()
        }.timeout(5.seconds)

        flow.collect { result.add(it) }
        assertEquals(listOf(1, 2), result)
    }

    @Test
    fun testCallbackFlowEmitThenCloseWithExceptionAndTimeout() = runTest {
        val result = mutableListOf<Int>()
        val flow = callbackFlow {
            send(1)
            close(IllegalStateException("Test Exception after emit"))
        }.timeout(5.seconds)

        val exception = assertFailsWith<IllegalStateException> {
            flow.collect { result.add(it) }
        }
        assertEquals("Test Exception after emit", exception.message)
        assertEquals(listOf(1), result)
    }
}
